import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { getComplaintById, updateComplaint } from '../services/api'; // Correct the import
import '../styles/style.css';

function ComplaintDetail({ complaint }) {
  const [message, setMessage] = useState(complaint?.message || ''); // Store current message
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false); // For loading state
  const [chatMessage, setChatMessage] = useState('');
  const [complaintDetails, setComplaintDetails] = useState(complaint);
  const navigate = useNavigate(); // Initialize navigate hook
  const { complaintId } = useParams(); // Get complaintId from URL if needed

  // Fetch complaint details when the component mounts (if no initial complaint passed as props)
  useEffect(() => {
    if (!complaint) {
      setLoading(true);
      fetchComplaint(complaintId) // API to fetch the complaint details
        .then((data) => {
          setComplaintDetails(data);
          setLoading(false);
        })
        .catch((err) => {
          setError('Failed to load complaint');
          setLoading(false);
        });
    }
  }, [complaintId, complaint]);

  const handleUpdate = async (e) => {
    e.preventDefault();

    if (!message.trim()) {
      setError('Message cannot be empty');
      return;
    }

    try {
      setLoading(true);
      const token = localStorage.getItem('token');
      await updateComplaint(complaintDetails._id, { message }, token); // Send message update to backend
      setLoading(false);
      navigate('/complaints'); // Use navigate to redirect to complaints list page after update
    } catch (err) {
      setLoading(false);
      setError('Failed to update complaint');
    }
  };

  const handleChatSubmit = async (e) => {
    e.preventDefault();

    if (!chatMessage.trim()) {
      setError('Message cannot be empty');
      return;
    }

    try {
      setLoading(true);
      const token = localStorage.getItem('token');
      await updateComplaint(complaintDetails._id, { chatMessage }, token); // Assuming you have an endpoint for chat messages
      setLoading(false);
      setChatMessage('');
      setComplaintDetails((prevState) => ({
        ...prevState,
        chat: [...prevState.chat, { user: { email: 'Logged in User' }, message: chatMessage, date: new Date() }]
      })); // Update chat state with new message
    } catch (err) {
      setLoading(false);
      setError('Failed to send chat message');
    }
  };

  return (
    <div className="complaint-detail-container">
      {loading ? (
        <p>Loading...</p> // Loading state
      ) : complaintDetails ? (
        <div className="complaint-card">
          <h2>{complaintDetails.title}</h2>
          <p><strong>Description:</strong> {complaintDetails.description}</p>
          <p><strong>Status:</strong> {complaintDetails.status}</p>
          <p><strong>Created At:</strong> {new Date(complaintDetails.createdAt).toLocaleString()}</p>
          <p><strong>Updated At:</strong> {new Date(complaintDetails.updatedAt).toLocaleString()}</p>

          {complaintDetails.image && (
            <div className="complaint-image">
              <img
                src={complaintDetails.image}
                alt="Complaint"
                className="complaint-thumbnail"
              />
            </div>
          )}

          {complaintDetails.student && (
            <p><strong>Filed By:</strong> {complaintDetails.student.email} ({complaintDetails.student.role})</p>
          )}

          {/* Update message section */}
          <h3>Update Complaint Message</h3>
          <form onSubmit={handleUpdate}>
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              rows="4"
              placeholder="Enter your updated message here"
            />
            {error && <p className="error">{error}</p>}
            <button type="submit" disabled={loading}>
              {loading ? 'Updating...' : 'Update Message'}
            </button>
          </form>

          {/* Chat Section */}
          {complaintDetails.chat?.length > 0 && (
            <div className="chat-section">
              <h4>Chat History</h4>
              <ul>
                {complaintDetails.chat.map((msg, index) => (
                  <li key={index}>
                    <strong>{msg.user?.email || 'Unknown'}:</strong> {msg.message}
                    <br />
                    <small>{new Date(msg.date).toLocaleString()}</small>
                  </li>
                ))}
              </ul>
            </div>
          )}

          {/* Send Chat Message */}
          <h3>Send Chat Message</h3>
          <form onSubmit={handleChatSubmit}>
            <textarea
              value={chatMessage}
              onChange={(e) => setChatMessage(e.target.value)}
              rows="4"
              placeholder="Enter your chat message here"
            />
            {error && <p className="error">{error}</p>}
            <button type="submit" disabled={loading}>
              {loading ? 'Sending...' : 'Send Chat'}
            </button>
          </form>
        </div>
      ) : (
        <p>Complaint not found</p>
      )}
    </div>
  );
}

export default ComplaintDetail;
